package main

import "log"

// Compliant: Clear intentions with comments or implementations
func processData(data []string) {
    for _, item := range data {
        if len(item) > 0 {
            // GOOD: Clear comment explaining intention
            // TODO: Add validation logic in next sprint
            log.Printf("Processing item: %s", item)
        }
    }

    switch data[0] {
    case "start":
        // GOOD: Explicit no-op with explanation
        // Start command is handled by external service
        log.Println("Start command received - delegated to service")
    case "stop":
        stopProcess()
    default:
        // GOOD: Proper default handling
        log.Printf("Unknown command: %s", data[0])
        handleUnknownCommand(data[0])
    }
}

func handleError(err error) {
    if err != nil {
        // GOOD: Proper error handling
        log.Printf("Error occurred: %v", err)
        notifyErrorService(err)
    }
}

// GOOD: Proper error recovery
func riskyOperation() {
    defer func() {
        if r := recover(); r != nil {
            // GOOD: Meaningful recovery handling
            log.Printf("Recovered from panic: %v", r)
            sendAlert("Panic recovered in riskyOperation")
        }
    }()

    // Some risky code
    performCriticalTask()
}

// Alternative: Remove unnecessary blocks
func processDataSimplified(data []string) {
    for _, item := range data {
        // GOOD: Removed empty block entirely
        if len(item) > 0 {
            log.Printf("Processing item: %s", item)
        }
    }
}

// GOOD: Use explicit panic handling
func saferOperation() error {
    defer func() {
        if r := recover(); r != nil {
            log.Printf("Operation failed: %v", r)
        }
    }()

    return performCriticalTask()
}
